// n8n Code Node
// Mode: Run Once for All Items

const rows = items.map(item => item.json);

// ----------------------
// KPI Variables
// ----------------------
let totalRevenue = 0;
let totalOrders = rows.length;
let totalQuantity = 0;

const itemSales = {};
const regionSales = {};
const channelSales = {};
const hourlySales = {};
const dailySales = {};

// ----------------------
// Calculate KPIs
// ----------------------

for (const row of rows) {

    const revenue = Number(row.revenue || 0);
    const qty = Number(row.quantity || 0);

    totalRevenue += revenue;
    totalQuantity += qty;

    // Product Sales
    itemSales[row.item] = (itemSales[row.item] || 0) + revenue;

    // Region Sales
    regionSales[row.region] = (regionSales[row.region] || 0) + revenue;

    // Channel Sales
    channelSales[row.channel] = (channelSales[row.channel] || 0) + revenue;

    // Daily Sales
    dailySales[row.date] = (dailySales[row.date] || 0) + revenue;

    // Hourly Sales
    if (row.time) {
        const hour = row.time.split(":")[0];
        hourlySales[hour] = (hourlySales[hour] || 0) + revenue;
    }

}

// ----------------------
// Helper Function
// ----------------------

function topEntry(obj){
    return Object.entries(obj)
        .sort((a,b)=>b[1]-a[1])[0];
}

function bottomEntry(obj){
    return Object.entries(obj)
        .sort((a,b)=>a[1]-b[1])[0];
}

// ----------------------
// KPIs
// ----------------------

const averageOrderValue =
    totalOrders ? totalRevenue / totalOrders : 0;

const averageQuantity =
    totalOrders ? totalQuantity / totalOrders : 0;

const topProduct = topEntry(itemSales);
const topRegion = topEntry(regionSales);
const topChannel = topEntry(channelSales);
const peakHour = topEntry(hourlySales);
const bestDay = topEntry(dailySales);

const lowestProduct = bottomEntry(itemSales);
const lowestRegion = bottomEntry(regionSales);

// ----------------------
// Output
// ----------------------

return [
{
json:{

dataset_summary:{

total_orders:totalOrders,

total_revenue:totalRevenue,

total_quantity:totalQuantity,

average_order_value:Number(averageOrderValue.toFixed(2)),

average_quantity_per_order:Number(averageQuantity.toFixed(2)),

top_selling_product:{
name:topProduct?.[0],
revenue:topProduct?.[1]
},

lowest_selling_product:{
name:lowestProduct?.[0],
revenue:lowestProduct?.[1]
},

top_region:{
name:topRegion?.[0],
revenue:topRegion?.[1]
},

lowest_region:{
name:lowestRegion?.[0],
revenue:lowestRegion?.[1]
},

best_sales_channel:{
name:topChannel?.[0],
revenue:topChannel?.[1]
},

peak_sales_hour:{
hour:peakHour?.[0]+":00",
revenue:peakHour?.[1]
},

best_sales_day:{
date:bestDay?.[0],
revenue:bestDay?.[1]
},

product_sales:itemSales,

region_sales:regionSales,

channel_sales:channelSales,

hourly_sales:hourlySales,

daily_sales:dailySales

}

}
}
];
